# OEIS sequence: A394228

def a(n):
    if n == 1: return 1
    seen, modder = dict(), 10**n
    pow2mod = pow(2, 3*n, modder)
    for k in range(3*n, modder+1):
        s = str(pow2mod)
        if len(s) == n:
            key = "".join(sorted(s))
            if key in seen and seen[key][0] != s:
                return seen[key][1]
            else:
                seen[key] = (s, k)
        pow2mod = 2*pow2mod%modder
    return -1
print([a(n) for n in range(1, 51)]) # _Michael S. Branicky_, May 28 2026

